    with open(os.path.join(tmpdir, "Program.cs"), 'w') as f:
        f.write(code)
    result = subprocess.run(['dotnet', 'run', '--project', os.path.join(tmpdir, 'check.csproj')], capture_output=True, text=True, timeout=60)
    print(result.stdout)
EOF

